mapper.select:
SELECT r.id, r.student_id AS studentId, s.name AS studentName, r.info, r.contact_time AS contactTime, r.contact_next_time AS contactNextTime, r.contact_type AS contactType, r.contact_phone AS contactPhone, r.stage, r.creator, r.add_time AS addTime FROM contact_record r LEFT JOIN student s ON r.student_id = s.id AND s.deleted = 0
r.deleted = 0
AND (s.name LIKE CONCAT('%', #{condition.keyword}, '%') OR r.contact_phone LIKE CONCAT('%', #{condition.keyword}, '%'))
AND r.stage = #{condition.stage}
AND r.creator = #{condition.creator}
AND r.contact_time >= #{condition.startTime}
AND r.contact_time <= #{condition.endTime}
AND r.student_id = #{condition.studentId}
ORDER BY r.contact_time DESC
